  1	import { isModelFeatureFlag, ModelFeatureFlag, useResolvedExtensions } from '@openshift-console/dynamic-plugin-sdk';
  2	import { Button, Flex, FlexItem, PageSection, Text, TextVariants, Title } from '@patternfly/react-core';
  3	import { SyncAltIcon } from '@patternfly/react-icons';
  4	import * as _ from 'lodash';
  5	import * as React from 'react';
  6	import { useTranslation } from 'react-i18next';
  7	import { Record } from '../api/ipfix';
  8	import { defaultNetflowMetrics } from '../api/loki';
  9	import { Config, defaultConfig } from '../model/config';
 10	import { DisabledFilters, Filters, getDisabledFiltersRecord } from '../model/filters';
 11	import {
 12	  DataSource,
 13	  FlowScope,
 14	  isTimeMetric,
 15	  MetricType,
 16	  PacketLoss,
 17	  RecordType,
 18	  StatFunction
 19	} from '../model/flow-query';
 20	import { FetchCallbacks, NetflowContext, NetflowContextValue } from '../model/netflow-context';
 21	import { getGroupsForScope } from '../model/scope';
 22	import { DefaultOptions, GraphElementPeer, TopologyOptions } from '../model/topology';
 23	import { Column, ColumnSizeMap } from '../utils/columns';
 24	import { useConfigValidation } from '../utils/config-validation-hook';
 25	import { ContextSingleton } from '../utils/context';
 26	import { TimeRange } from '../utils/datetime';
 27	import { useFullScreen } from '../utils/fullscreen-hook';
 28	import { useK8sModelsWithColors } from '../utils/k8s-models-hook';
 29	import {
 30	  defaultArraySelectionOptions,
 31	  localStorageColsKey,
 32	  localStorageColsSizesKey,
 33	  localStorageDisabledFiltersKey,
 34	  localStorageLastLimitKey,
 35	  localStorageLastTopKey,
 36	  localStorageMetricFunctionKey,
 37	  localStorageMetricScopeKey,
 38	  localStorageMetricTypeKey,
 39	  localStorageOverviewFocusKey,
 40	  localStorageOverviewIdsKey,
 41	  localStorageOverviewTruncateKey,
 42	  localStorageQueryParamsKey,
 43	  localStorageRefreshKey,
 44	  localStorageShowHistogramKey,
 45	  localStorageShowOptionsKey,
 46	  localStorageSizeKey,
 47	  localStorageTopologyOptionsKey,
 48	  localStorageViewIdKey,
 49	  useLocalStorage
 50	} from '../utils/local-storage-hook';
 51	import { useConfigCapabilities } from '../utils/netflow-capabilities-hook';
 52	import { InitState, useDataFetching } from '../utils/netflow-fetching-hook';
 53	import { OverviewPanel } from '../utils/overview-panels';
 54	import {
 55	  defaultMetricFunction,
 56	  defaultMetricScope,
 57	  defaultMetricType,
 58	  defaultTimeRange,
 59	  getDataSourceFromURL,
 60	  getFiltersFromURL,
 61	  getLimitFromURL,
 62	  getPacketLossFromURL,
 63	  getRangeFromURL,
 64	  getRecordTypeFromURL,
 65	  getShowDupFromURL,
 66	  setURLFilters
 67	} from '../utils/router';
 68	import { useTheme } from '../utils/theme-hook';
 69	import { netflowTrafficPath, useNavigate } from '../utils/url';
 70	import { useURLSync } from '../utils/url-sync-hook';
 71	import NetflowTrafficDrawer, { NetflowTrafficDrawerHandle } from './drawer/netflow-traffic-drawer';
 72	import { rateMetricFunctions, timeMetricFunctions } from './dropdowns/metric-function-dropdown';
 73	import { limitValues, topValues } from './dropdowns/query-options-panel';
 74	import { RefreshDropdown } from './dropdowns/refresh-dropdown';
 75	import TimeRangeDropdown from './dropdowns/time-range-dropdown';
 76	import { TruncateLength } from './dropdowns/truncate-dropdown';
 77	import GuidedTourPopover, { GuidedTourHandle } from './guided-tour/guided-tour';
 78	import Modals from './modals/modals';
 79	import './netflow-traffic.css';
 80	import { SearchEvent, SearchHandle } from './search/search';
 81	import TabsContainer from './tabs/tabs-container';
 82	import { FiltersToolbar } from './toolbar/filters-toolbar';
 83	import ChipsPopover from './toolbar/filters/chips-popover';
 84	import HistogramToolbar from './toolbar/histogram-toolbar';
 85	import ViewOptionsToolbar from './toolbar/view-options-toolbar';
 86	
 87	export type ViewId = 'overview' | 'table' | 'topology';
 88	export type Size = 's' | 'm' | 'l';
 89	
 90	export interface NetflowTrafficProps {
 91	  forcedNamespace?: string;
 92	  forcedFilters?: Filters | null;
 93	  isTab?: boolean;
 94	  hideTitle?: boolean;
 95	  parentConfig?: Config;
 96	}
 97	
 98	export const NetflowTraffic: React.FC<NetflowTrafficProps> = ({
 99	  forcedNamespace,
100	  forcedFilters,
101	  isTab,
102	  hideTitle,
103	  parentConfig
104	}) => {
105	  const { t } = useTranslation('plugin__netobserv-plugin');
106	  const navigate = useNavigate();
107	  const isDarkTheme = useTheme();
108	  const [extensions] = useResolvedExtensions<ModelFeatureFlag>(isModelFeatureFlag);
109	  ContextSingleton.setContext(forcedNamespace);
110	
111	  // ===== STATE MANAGEMENT =====
112	  // Config state
113	  const [config, setConfig] = React.useState<Config>(defaultConfig);
114	  const k8sModels = useK8sModelsWithColors();
115	
116	  // Local storage hooks
117	  const [queryParams, setQueryParams] = useLocalStorage<string>(localStorageQueryParamsKey);
118	  const [disabledFilters, setDisabledFilters] = useLocalStorage<DisabledFilters>(localStorageDisabledFiltersKey, {});
119	  const [size, setSize] = useLocalStorage<Size>(localStorageSizeKey, 'm');
120	  const [selectedViewId, setSelectedViewId] = useLocalStorage<ViewId>(localStorageViewIdKey, 'overview');
121	  const [lastLimit, setLastLimit] = useLocalStorage<number>(localStorageLastLimitKey, limitValues[0]);
122	  const [lastTop, setLastTop] = useLocalStorage<number>(localStorageLastTopKey, topValues[0]);
123	  const [metricScope, setMetricScope] = useLocalStorage<FlowScope>(localStorageMetricScopeKey, defaultMetricScope);
124	  const [topologyMetricFunction, setTopologyMetricFunction] = useLocalStorage<StatFunction>(
125	    localStorageMetricFunctionKey,
126	    defaultMetricFunction
127	  );
128	  const [topologyMetricType, setTopologyMetricType] = useLocalStorage<MetricType>(
129	    localStorageMetricTypeKey,
130	    defaultMetricType
131	  );
132	  const [interval, setInterval] = useLocalStorage<number | undefined>(localStorageRefreshKey);
133	  const [showViewOptions, setShowViewOptions] = useLocalStorage<boolean>(localStorageShowOptionsKey, false);
134	  const [showHistogram, setShowHistogram] = useLocalStorage<boolean>(localStorageShowHistogramKey, false);
135	  const [overviewTruncateLength, setOverviewTruncateLength] = useLocalStorage<TruncateLength>(
136	    localStorageOverviewTruncateKey,
137	    TruncateLength.M
138	  );
139	  const [overviewFocus, setOverviewFocus] = useLocalStorage<boolean>(localStorageOverviewFocusKey, false);
140	  const [topologyOptions, setTopologyOptions] = useLocalStorage<TopologyOptions>(
141	    localStorageTopologyOptionsKey,
142	    DefaultOptions
143	  );
144	  const [panels, setPanels] = useLocalStorage<OverviewPanel[]>(
145	    localStorageOverviewIdsKey,
146	    [],
147	    defaultArraySelectionOptions
148	  );
149	  const [columns, setColumns] = useLocalStorage<Column[]>(localStorageColsKey, [], defaultArraySelectionOptions);
150	  const [_columnSizes, setColumnSizes] = useLocalStorage<ColumnSizeMap>(localStorageColsSizesKey, {});
151	
152	  // Display state
153	  const [isViewOptionOverflowMenuOpen, setViewOptionOverflowMenuOpen] = React.useState(false);
154	  const [isFullScreen, setFullScreen] = useFullScreen();
155	  const [isShowQuerySummary, setShowQuerySummary] = React.useState<boolean>(false);
156	  const [isTRModalOpen, setTRModalOpen] = React.useState(false);
157	  const [isOverviewModalOpen, setOverviewModalOpen] = React.useState(false);
158	  const [isColModalOpen, setColModalOpen] = React.useState(false);
159	  const [isExportModalOpen, setExportModalOpen] = React.useState(false);
160	  const [filters, setFilters] = React.useState<Filters>({ list: [], match: 'all' });
161	  const [packetLoss, setPacketLoss] = React.useState<PacketLoss>(getPacketLossFromURL());
162	  const [recordType, setRecordType] = React.useState<RecordType>(getRecordTypeFromURL());
163	  const [dataSource, setDataSource] = React.useState<DataSource>(getDataSourceFromURL());
164	  const [showDuplicates, setShowDuplicates] = React.useState<boolean>(getShowDupFromURL());
165	  const [limit, setLimit] = React.useState<number>(
166	    getLimitFromURL(selectedViewId === 'table' ? limitValues[0] : topValues[0])
167	  );
168	  const [range, setRange] = React.useState<number | TimeRange>(getRangeFromURL());
169	  const [histogramRange, setHistogramRange] = React.useState<TimeRange>();
170	  const [_selectedRecord, setSelectedRecord] = React.useState<Record | undefined>(undefined);
171	  const [_selectedElement, setSelectedElement] = React.useState<GraphElementPeer | undefined>(undefined);
172	  const [_searchEvent, setSearchEvent] = React.useState<SearchEvent | undefined>(undefined);
173	
174	  // ===== SIDE EFFECTS =====
175	  // Set FlowCollector model in ContextSingleton when k8sModels change
176	  React.useEffect(() => {
177	    const flowCollectorModelKey = Object.keys(k8sModels).find(k => k.includes('FlowCollector'));
178	    if (flowCollectorModelKey) {
179	      ContextSingleton.setFlowCollectorK8SModel(k8sModels[flowCollectorModelKey]);
180	    }
181	  }, [k8sModels]);
182	
183	  // ===== CONFIG CAPABILITIES =====
184	  const caps = useConfigCapabilities({
185	    config,
186	    selectedViewId,
187	    dataSource,
188	    columns,
189	    panels,
190	    metricScope,
191	    topologyOptions,
192	    topologyMetricType,
193	    forcedNamespace,
194	    forcedFilters,
195	    filters,
196	    limit,
197	    recordType,
198	    packetLoss,
199	    range
200	  });
201	
202	  // ===== WRAPPED SETTERS FOR COMPLEX LOGIC =====
203	  const updateMetricScope = React.useCallback(
204	    (scope: FlowScope) => {
205	      setMetricScope(scope);
206	      // Invalidate groups if necessary, when metrics scope changed
207	      setTopologyOptions(prevOptions => {
208	        const groups = getGroupsForScope(scope, config.scopes);
209	        if (!groups.includes(prevOptions.groupTypes)) {
210	          return { ...prevOptions, groupTypes: 'auto' };
211	        }
212	        return prevOptions;
213	      });
214	    },
215	    [setMetricScope, config.scopes, setTopologyOptions]
216	  );
217	
218	  const updateTopologyMetricType = React.useCallback(
219	    (metricType: MetricType) => {
220	      if (isTimeMetric(metricType)) {
221	        // fallback on average if current function not available for time queries
222	        setTopologyMetricFunction(prevFunc => {
223	          if (!timeMetricFunctions.includes(prevFunc)) {
224	            return 'avg';
225	          }
226	          return prevFunc;
227	        });
228	      } else {
229	        // fallback on average if current function not available for rate queries
230	        setTopologyMetricFunction(prevFunc => {
231	          if (!rateMetricFunctions.includes(prevFunc)) {
232	            return 'avg';
233	          }
234	          return prevFunc;
235	        });
236	      }
237	      setTopologyMetricType(metricType);
238	    },
239	    [setTopologyMetricFunction, setTopologyMetricType]
240	  );
241	
242	  // Refs
243	  const drawerRef = React.useRef<NetflowTrafficDrawerHandle>(null);
244	  const searchRef = React.useRef<SearchHandle>(null);
245	  const guidedTourRef = React.useRef<GuidedTourHandle>(null);
246	  const initState = React.useRef<InitState>([]);
247	
248	  // Data-fetching hook
249	  const {
250	    loading,
251	    error,
252	    flows,
253	    stats,
254	    metrics,
255	    metricsRef,
256	    lastRefresh,
257	    lastDuration,
258	    warning,
259	    chipsPopoverMessage,
260	    setChipsPopoverMessage,
261	    topologyUDNIds,
262	    tick,
263	    updateTableFilters,
264	    setFlows,
265	    setMetrics,
266	    setError
267	  } = useDataFetching({
268	    drawerRef,
269	    initState,
270	    caps,
271	    config,
272	    selectedViewId,
273	    range,
274	    histogramRange,
275	    showHistogram,
276	    showDuplicates,
277	    metricScope,
278	    topologyMetricType,
279	    topologyMetricFunction,
280	    topologyOptions,
281	    interval,
282	    isTRModalOpen,
283	    isOverviewModalOpen,
284	    isColModalOpen,
285	    isExportModalOpen,
286	    filters,
287	    setFilters,
288	    parentConfig,
289	    forcedFilters,
290	    setConfig,
291	    queryParams
292	  });
293	
294	  const resetDefaultFilters = React.useCallback(() => {
295	    updateTableFilters({ match: filters.match, list: caps.defaultFilters });
296	  }, [filters.match, caps.defaultFilters, updateTableFilters]);
297	
298	  const setFiltersFromURL = React.useCallback(() => {
299	    if (forcedFilters === null) {
300	      const filtersPromise = getFiltersFromURL(caps.filterDefs, disabledFilters);
301	      if (filtersPromise) {
302	        initState.current.push('urlFiltersPending');
303	        filtersPromise.then(updateTableFilters);
304	      } else {
305	        resetDefaultFilters();
306	      }
307	    }
308	  }, [disabledFilters, forcedFilters, caps.filterDefs, resetDefaultFilters, updateTableFilters]);
309	
310	  const clearFilters = React.useCallback(() => {
311	    if (forcedFilters) {
312	      navigate(netflowTrafficPath);
313	    } else if (filters) {
314	      //set URL Param to empty value to be able to restore state coming from another page
315	      const empty: Filters = { ...filters, list: [], match: 'all' };
316	      setURLFilters(empty);
317	      updateTableFilters(empty);
318	    }
319	  }, [forcedFilters, filters, navigate, updateTableFilters]);
320	
321	  // Effects
322	
323	  // Validate and coerce state when config/capabilities change
324	  useConfigValidation({
325	    initState,
326	    config,
327	    caps,
328	    filters,
329	    updateTableFilters,
330	    recordType,
331	    setRecordType,
332	    dataSource,
333	    setDataSource,
334	    packetLoss,
335	    setPacketLoss,
336	    metricScope,
337	    setMetricScope,
338	    topologyMetricType,
339	    setTopologyMetricType,
340	    setColumns,
341	    setPanels,
342	    setFiltersFromURL
343	  });
344	
345	  // Sync state to URL params
346	  useURLSync({
347	    initState,
348	    filters,
349	    forcedFilters,
350	    range,
351	    limit,
352	    showDuplicates,
353	    topologyMetricFunction,
354	    topologyMetricType,
355	    selectedViewId,
356	    packetLoss,
357	    recordType,
358	    dataSource,
359	    setQueryParams,
360	    setTRModalOpen
361	  });
362	
363	  // update local storage enabled filters
364	  React.useEffect(() => {
365	    if (initState.current.includes('configLoaded')) {
366	      setDisabledFilters(getDisabledFiltersRecord(filters.list));
367	    }
368	    // eslint-disable-next-line react-hooks/exhaustive-deps
369	  }, [filters]);
370	
371	  // Functions
372	  const clearSelections = () => {
373	    setTRModalOpen(false);
374	    setOverviewModalOpen(false);
375	    setColModalOpen(false);
376	    setSelectedRecord(undefined);
377	    setShowQuerySummary(false);
378	    setSelectedElement(undefined);
379	  };
380	
381	  const selectView = (view: ViewId) => {
382	    clearSelections();
383	    //save / restore top / limit parameter according to selected view
384	    if (view === 'overview' && selectedViewId !== 'overview') {
385	      setLastLimit(limit);
386	      setLimit(lastTop);
387	    } else if (view !== 'overview' && selectedViewId === 'overview') {
388	      setLastTop(limit);
389	      setLimit(lastLimit);
390	    }
391	
392	    if (view !== selectedViewId) {
393	      setFlows([]);
394	      setMetrics(defaultNetflowMetrics);
395	      if (!initState.current.includes('configLoadError')) {
396	        setError(undefined);
397	      }
398	    }
399	    setSelectedViewId(view);
400	  };
401	
402	  // Views
403	  const actions = () => {
404	    return (
405	      <Flex direction={{ default: 'row' }}>
406	        <FlexItem>
407	          <Flex direction={{ default: 'column' }}>
408	            <FlexItem className="netobserv-action-title">
409	              <Text component={TextVariants.h4}>{t('Time range')}</Text>
410	            </FlexItem>
411	            <FlexItem flex={{ default: 'flex_1' }}>
412	              <TimeRangeDropdown
413	                data-test="time-range-dropdown"
414	                id="time-range-dropdown"
415	                range={range}
416	                setRange={setRange}
417	                openCustomModal={() => setTRModalOpen(true)}
418	              />
419	            </FlexItem>
420	          </Flex>
421	        </FlexItem>
422	        <FlexItem className="netobserv-refresh-interval-container">
423	          <Flex direction={{ default: 'column' }}>
424	            <FlexItem className="netobserv-action-title">
425	              <Text component={TextVariants.h4}>{t('Refresh interval')}</Text>
426	            </FlexItem>
427	            <FlexItem flex={{ default: 'flex_1' }}>
428	              <RefreshDropdown
429	                data-test="refresh-dropdown"
430	                id="refresh-dropdown"
431	                disabled={showHistogram || typeof range !== 'number'}
432	                interval={interval}
433	                setInterval={setInterval}
434	              />
435	            </FlexItem>
436	          </Flex>
437	        </FlexItem>
438	        <FlexItem className="netobserv-refresh-container">
439	          <Button
440	            data-test="refresh-button"
441	            id="refresh-button"
442	            className="co-action-refresh-button"
443	            variant="primary"
444	            onClick={() => tick()}
445	            icon={<SyncAltIcon style={{ animation: `spin ${loading ? 1 : 0}s linear infinite` }} />}
446	          />
447	        </FlexItem>
448	      </Flex>
449	    );
450	  };
451	
452	  const pageHeader = () => {
453	    return (
454	      <div id="pageHeader">
455	        <Flex direction={{ default: 'row' }}>
456	          <FlexItem flex={{ default: 'flex_1' }}>
457	            <Title headingLevel={TextVariants.h1}>{t('Network Traffic')}</Title>
458	          </FlexItem>
459	          <FlexItem>{actions()}</FlexItem>
460	        </Flex>
461	      </div>
462	    );
463	  };
464	
465	  const isShowViewOptions = selectedViewId === 'table' ? showViewOptions && !showHistogram : showViewOptions;
466	
467	  const fetchCallbacks: FetchCallbacks = React.useMemo(
468	    () => ({ metricsRef, setFlows, setMetrics, setError }),
469	    [metricsRef, setFlows, setMetrics, setError]
470	  );
471	
472	  const contextValue: NetflowContextValue = React.useMemo(
473	    () => ({ caps, config, k8sModels, fetchCallbacks }),
474	    [caps, config, k8sModels, fetchCallbacks]
475	  );
476	
477	  return extensions && !_.isEmpty(extensions) ? (
478	    <NetflowContext.Provider value={contextValue}>
479	      <PageSection id="pageSection" className={`${isDarkTheme ? 'dark' : 'light'} ${isTab ? 'tab' : ''}`}>
480	        {!hideTitle && pageHeader()}
481	        {!_.isEmpty(caps.filterDefs) && (
482	          <Flex direction={{ default: 'row' }} style={{ paddingRight: hideTitle ? '1.5rem' : undefined }}>
483	            <FlexItem style={{ paddingTop: hideTitle ? '1.8rem' : undefined }} flex={{ default: 'flex_1' }}>
484	              <FiltersToolbar
485	                id="filter-toolbar"
486	                filters={filters}
487	                forcedFilters={forcedFilters}
488	                setFilters={updateTableFilters}
489	                clearFilters={clearFilters}
490	                resetFilters={resetDefaultFilters}
491	                queryOptionsProps={{
492	                  limit,
493	                  recordType,
494	                  dataSource,
495	                  packetLoss,
496	                  setLimit,
497	                  setRecordType,
498	                  setDataSource,
499	                  setPacketLoss,
500	                  allowLoki: caps.allowLoki,
501	                  allowProm: caps.allowProm,
502	                  allowFlow: caps.isFlow,
503	                  allowConnection: caps.isConnectionTracking,
504	                  allowPktDrops: caps.isPktDrop,
505	                  useTopK: selectedViewId === 'overview'
506	                }}
507	                isFullScreen={isFullScreen}
508	                setFullScreen={setFullScreen}
509	              />
510	            </FlexItem>
511	            {hideTitle && <FlexItem style={{ alignSelf: 'flex-start' }}>{actions()}</FlexItem>}
512	          </Flex>
513	        )}
514	        {
515	          <TabsContainer
516	            selectedViewId={selectedViewId}
517	            showHistogram={showHistogram}
518	            setShowViewOptions={setShowViewOptions}
519	            setShowHistogram={setShowHistogram}
520	            setHistogramRange={setHistogramRange}
521	            selectView={selectView}
522	            isShowViewOptions={isShowViewOptions}
523	            style={{ paddingRight: hideTitle ? '1.5rem' : undefined }}
524	          />
525	        }
526	        {selectedViewId === 'table' && showHistogram && (
527	          <HistogramToolbar
528	            loading={loading}
529	            lastRefresh={lastRefresh}
530	            limit={limit}
531	            range={range}
532	            setRange={setRange}
533	            histogramRange={histogramRange}
534	            setHistogramRange={setHistogramRange}
535	            totalMetric={metrics.totalFlowCount?.result}
536	            guidedTourHandle={guidedTourRef.current}
537	            resetRange={() => setRange(defaultTimeRange)}
538	            tick={tick}
539	          />
540	        )}
541	        {isShowViewOptions && (
542	          <ViewOptionsToolbar
543	            size={size}
544	            overviewFocus={overviewFocus}
545	            setOverviewFocus={setOverviewFocus}
546	            selectedViewId={selectedViewId}
547	            setOverviewModalOpen={setOverviewModalOpen}
548	            overviewTruncateLength={overviewTruncateLength}
549	            setOverviewTruncateLength={setOverviewTruncateLength}
550	            setSize={setSize}
551	            metricScope={metricScope}
552	            setMetricScope={updateMetricScope}
553	            topologyMetricType={topologyMetricType}
554	            setTopologyMetricType={updateTopologyMetricType}
555	            topologyMetricFunction={topologyMetricFunction}
556	            setTopologyMetricFunction={setTopologyMetricFunction}
557	            topologyOptions={topologyOptions}
558	            setTopologyOptions={setTopologyOptions}
559	            setColModalOpen={setColModalOpen}
560	            setExportModalOpen={setExportModalOpen}
561	            isViewOptionOverflowMenuOpen={isViewOptionOverflowMenuOpen}
562	            setViewOptionOverflowMenuOpen={setViewOptionOverflowMenuOpen}
563	            showDuplicates={showDuplicates}
564	            setShowDuplicates={setShowDuplicates}
565	            setSearchEvent={setSearchEvent}
566	            ref={searchRef}
567	          />
568	        )}
569	        {
570	          <NetflowTrafficDrawer
571	            ref={drawerRef}
572	            error={error}
573	            currentState={initState.current}
574	            selectedViewId={selectedViewId}
575	            limit={limit}
576	            recordType={recordType}
577	            metrics={metrics}
578	            loading={loading}
579	            overviewTruncateLength={overviewTruncateLength}
580	            overviewFocus={overviewFocus}
581	            setOverviewFocus={setOverviewFocus}
582	            flows={flows}
583	            selectedRecord={_selectedRecord}
584	            setColumns={setColumns}
585	            columnSizes={_columnSizes}
586	            setColumnSizes={setColumnSizes}
587	            size={size}
588	            resetDefaultFilters={resetDefaultFilters}
589	            clearFilters={clearFilters}
590	            filters={filters}
591	            topologyMetricFunction={topologyMetricFunction}
592	            topologyMetricType={topologyMetricType}
593	            topologyUDNIds={topologyUDNIds}
594	            metricScope={metricScope}
595	            setMetricScope={updateMetricScope}
596	            topologyOptions={topologyOptions}
597	            setTopologyOptions={setTopologyOptions}
598	            setFilters={updateTableFilters}
599	            selectedElement={_selectedElement}
600	            searchHandle={searchRef.current}
601	            searchEvent={_searchEvent}
602	            isShowQuerySummary={isShowQuerySummary}
603	            lastRefresh={lastRefresh}
604	            range={range}
605	            setRange={setRange}
606	            setRecordType={setRecordType}
607	            stats={stats}
608	            lastDuration={lastDuration}
609	            warning={warning}
610	            setShowQuerySummary={setShowQuerySummary}
611	            clearSelections={clearSelections}
612	            setSelectedRecord={setSelectedRecord}
613	            setSelectedElement={setSelectedElement}
614	          />
615	        }
616	        {initState.current.includes('initDone') && (
617	          <Modals
618	            isTRModalOpen={isTRModalOpen}
619	            setTRModalOpen={setTRModalOpen}
620	            range={range}
621	            setRange={setRange}
622	            isOverviewModalOpen={isOverviewModalOpen}
623	            setOverviewModalOpen={setOverviewModalOpen}
624	            setPanels={setPanels}
625	            isColModalOpen={isColModalOpen}
